INSERT INTO vehicle (vehicle_id, vehicle_name, vehicle_name_ko, brand_id, brand_name, brand_name_ko, category, segment, body_type, seating, min_price, max_price, description, summary) VALUES
(1001, 'ST1', 'ST1', 1, 'Hyundai', '현대', 'truck', 'Commercial', 'Electric Van/Truck', 2, 56550000, 65000000, '현대 ST1은 전기 상용차 플랫폼을 기반으로 한 업무용 차량으로, 물류와 배송, 특장 용도에 맞춰 설계된 모델이다. 순수 전기 파워트레인을 기반으로 정숙한 주행감과 낮은 운행비, 충전 인프라 활용성을 제공한다. 2인승 구조와 적재 중심의 차체 구성을 바탕으로 물류, 업무, 레저, 사업용 운행에 적합하다. 주요 사양은 적재 형태와 특장 구성에 따라 달라지며, 내구성, 운행 효율, 업무 편의성이 중요한 선택 기준이다. 국내 판매 가격은 약 5,655만~6,500만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 ST1은 전기 상용차 플랫폼을 기반으로 한 업무용 차량으로, 물류와 배송, 특장 용도에 맞춰 설계된 모델이다.'),
(1002, 'The New Grandeur', '더 뉴 그랜저', 1, 'Hyundai', '현대', 'sedan', 'Full-size', 'Sedan', 5, 41850000, 58000000, '현대 더 뉴 그랜저는 준대형 세단으로, 고급스러운 실내와 편안한 승차감을 중시하는 소비자를 위한 현대의 대표 플래그십 세단이다. 파워트레인은 LPG, 가솔린, 하이브리드 구성을 제공해 주행 성향과 유지비 기준에 맞춰 선택할 수 있다. 5인승 구조를 바탕으로 출퇴근, 장거리 이동, 가족용 또는 비즈니스 이동에 안정적으로 대응한다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 4,185만~5,800만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 더 뉴 그랜저는 준대형 세단으로, 고급스러운 실내와 편안한 승차감을 중시하는 소비자를 위한 현대의 대표 플래그십 세단이다.'),
(1003, 'The All-New Nexo', '디 올 뉴 넥쏘', 1, 'Hyundai', '현대', 'suv', 'Compact', 'FCEV SUV', 5, 76430000, 82000000, '현대 디 올 뉴 넥쏘는 수소전기 SUV로, 배터리 전기차와 달리 수소 충전을 통해 전기 모터를 구동하는 친환경 차량이다. 수소전기 파워트레인을 기반으로 빠른 충전 시간과 친환경 주행 특성을 제공한다. 5인승 구조를 바탕으로 일상 주행과 가족 이동, 장거리 이동에 활용할 수 있다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 7,643만~8,200만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 디 올 뉴 넥쏘는 수소전기 SUV로, 배터리 전기차와 달리 수소 충전을 통해 전기 모터를 구동하는 친환경 차량이다.'),
(1004, 'The All-New Palisade', '디 올 뉴 팰리세이드', 1, 'Hyundai', '현대', 'suv', 'Large', 'SUV', 7, 43830000, 65000000, '현대 디 올 뉴 팰리세이드는 대형 SUV로, 넓은 실내와 3열 활용성을 중시하는 가족 고객을 위한 모델이다. 파워트레인은 가솔린, 하이브리드 구성을 제공해 주행 성향과 유지비 기준에 맞춰 선택할 수 있다. 7인승 구조를 바탕으로 일상 주행과 가족 이동, 장거리 이동에 활용할 수 있다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 4,383만~6,500만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 디 올 뉴 팰리세이드는 대형 SUV로, 넓은 실내와 3열 활용성을 중시하는 가족 고객을 위한 모델이다.'),
(1005, 'Mighty', '마이티', 1, 'Hyundai', '현대', 'truck', 'Commercial', 'Medium Truck', 3, 55000000, 90000000, '현대 마이티는 중소형 상용 트럭으로, 포터보다 디젤 파워트레인을 중심으로 장거리 주행 효율과 높은 토크를 제공한다. 3인승 구조와 적재 중심의 차체 구성을 바탕으로 물류, 업무, 레저, 사업용 운행에 적합하다. 주요 사양은 적재 형태와 특장 구성에 따라 달라지며, 내구성, 운행 효율, 업무 편의성이 중요한 선택 기준이다. 국내 판매 가격은 약 5,500만~9,000만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 마이티는 중소형 상용 트럭으로, 포터보다'),
(1006, 'Venue', '베뉴', 1, 'Hyundai', '현대', 'suv', 'Subcompact', 'SUV', 5, 21460000, 27000000, '현대 베뉴는 소형 SUV로, 합리적인 가격과 높은 시야, 간결한 운전 감각을 원하는 소비자를 위한 모델이다. 가솔린 파워트레인을 중심으로 안정적인 출력과 일상 주행 편의성을 제공한다. 5인승 구조를 바탕으로 일상 주행과 가족 이동, 장거리 이동에 활용할 수 있다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 2,146만~2,700만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 베뉴는 소형 SUV로, 합리적인 가격과 높은 시야, 간결한 운전 감각을 원하는 소비자를 위한 모델이다.'),
(1007, 'Staria', '스타리아', 1, 'Hyundai', '현대', 'suv', 'Large', 'MPV', 9, 32590000, 65490000, '현대 스타리아는 대형 MPV 및 승합 모델로, 넓은 실내와 다양한 좌석 구성을 바탕으로 가족용, 업무용, 의전용까지 폭넓게 활용된다. 파워트레인은 EV, LPG, 디젤, 하이브리드 구성을 제공해 주행 성향과 유지비 기준에 맞춰 선택할 수 있다. 9인승 구조를 바탕으로 가족 이동, 다인승 운송, 캠핑, 업무용 이동 등 넓은 공간이 필요한 용도에 적합하다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 3,259만~6,549만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 스타리아는 대형 MPV 및 승합 모델로, 넓은 실내와 다양한 좌석 구성을 바탕으로 가족용, 업무용, 의전용까지 폭넓게 활용된다.'),
(1008, 'Santa Fe', '싼타페', 1, 'Hyundai', '현대', 'suv', 'Mid-size', 'SUV', 5, 36060000, 53000000, '현대 싼타페는 중형 SUV로, 가족 이동과 캠핑, 장거리 주행 수요를 겨냥한 현대의 대표 패밀리 SUV다. 파워트레인은 가솔린, 하이브리드 구성을 제공해 주행 성향과 유지비 기준에 맞춰 선택할 수 있다. 5인승 구조를 바탕으로 일상 주행과 가족 이동, 장거리 이동에 활용할 수 있다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 3,606만~5,300만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 싼타페는 중형 SUV로, 가족 이동과 캠핑, 장거리 주행 수요를 겨냥한 현대의 대표 패밀리 SUV다.'),
(1009, 'Sonata The Edge', '쏘나타 디 엣지', 1, 'Hyundai', '현대', 'sedan', 'Mid-size', 'Sedan', 5, 28260000, 43000000, '현대 쏘나타 디 엣지는 중형 세단으로, 세련된 디자인과 안정적인 승차감, 넓은 실내 공간을 갖춘 대표 패밀리 세단이다. 파워트레인은 LPG, 가솔린, 하이브리드 구성을 제공해 주행 성향과 유지비 기준에 맞춰 선택할 수 있다. 5인승 구조를 바탕으로 출퇴근, 장거리 이동, 가족용 또는 비즈니스 이동에 안정적으로 대응한다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 2,826만~4,300만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 쏘나타 디 엣지는 중형 세단으로, 세련된 디자인과 안정적인 승차감, 넓은 실내 공간을 갖춘 대표 패밀리 세단이다.'),
(1010, 'Avante', '아반떼', 1, 'Hyundai', '현대', 'sedan', 'Compact', 'Sedan', 5, 20340000, 33000000, '현대 아반떼는 국내 준중형 세단 시장을 대표하는 모델로, 출퇴근과 일상 주행, 첫 차 수요까지 폭넓게 대응하는 실용형 세단이다. 파워트레인은 LPG, 가솔린, 하이브리드 구성을 제공해 주행 성향과 유지비 기준에 맞춰 선택할 수 있다. 5인승 구조를 바탕으로 출퇴근, 장거리 이동, 가족용 또는 비즈니스 이동에 안정적으로 대응한다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 2,034만~3,300만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 아반떼는 국내 준중형 세단 시장을 대표하는 모델로, 출퇴근과 일상 주행, 첫 차 수요까지 폭넓게 대응하는 실용형 세단이다.'),
(1011, 'Ioniq 5', '아이오닉 5', 1, 'Hyundai', '현대', 'suv', 'Mid-size', 'Electric Crossover', 5, 47350000, 62000000, '현대 아이오닉 5는 전기차 전용 플랫폼 기반의 중형 전기 크로스오버로, 넓은 실내 공간과 빠른 충전 편의성이 강점인 모델이다. 순수 전기 파워트레인을 기반으로 정숙한 주행감과 낮은 운행비, 충전 인프라 활용성을 제공한다. 5인승 구조를 바탕으로 일상 주행과 가족 이동, 장거리 이동에 활용할 수 있다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 4,735만~6,200만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 아이오닉 5는 전기차 전용 플랫폼 기반의 중형 전기 크로스오버로, 넓은 실내 공간과 빠른 충전 편의성이 강점인 모델이다.'),
(1012, 'Ioniq 6', '아이오닉 6', 1, 'Hyundai', '현대', 'sedan', 'Mid-size', 'Electric Sedan', 5, 48560000, 62000000, '현대 아이오닉 6는 전기차 전용 플랫폼을 기반으로 한 전기 세단으로, 공기역학적 디자인과 장거리 주행 효율을 중시한 모델이다. 순수 전기 파워트레인을 기반으로 정숙한 주행감과 낮은 운행비, 충전 인프라 활용성을 제공한다. 5인승 구조를 바탕으로 출퇴근, 장거리 이동, 가족용 또는 비즈니스 이동에 안정적으로 대응한다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 4,856만~6,200만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 아이오닉 6는 전기차 전용 플랫폼을 기반으로 한 전기 세단으로, 공기역학적 디자인과 장거리 주행 효율을 중시한 모델이다.'),
(1013, 'Ioniq 9', '아이오닉 9', 1, 'Hyundai', '현대', 'suv', 'Large', 'Electric SUV', 7, 67590000, 85000000, '현대 아이오닉 9은 대형 전기 SUV로, 전기차 전용 플랫폼의 공간 효율과 3열 SUV의 실용성을 결합한 모델이다. 순수 전기 파워트레인을 기반으로 정숙한 주행감과 낮은 운행비, 충전 인프라 활용성을 제공한다. 7인승 구조를 바탕으로 일상 주행과 가족 이동, 장거리 이동에 활용할 수 있다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 6,759만~8,500만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 아이오닉 9은 대형 전기 SUV로, 전기차 전용 플랫폼의 공간 효율과 3열 SUV의 실용성을 결합한 모델이다.'),
(1014, 'Casper', '캐스퍼', 1, 'Hyundai', '현대', 'micro', 'Minicar', 'Crossover', 4, 14600000, 33000000, '현대 캐스퍼는 경형 SUV 성격의 소형 크로스오버로, 도심 주행과 좁은 주차 환경에 최적화된 모델이다. 가솔린 파워트레인을 중심으로 안정적인 출력과 일상 주행 편의성을 제공한다. 4인승 구조와 부담 없는 차체 크기를 바탕으로 도심 주행, 출퇴근, 첫 차, 세컨드카 용도에 적합하다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 1,460만~3,300만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 캐스퍼는 경형 SUV 성격의 소형 크로스오버로, 도심 주행과 좁은 주차 환경에 최적화된 모델이다.'),
(1015, 'Kona', '코나', 1, 'Hyundai', '현대', 'suv', 'Subcompact', 'SUV', 5, 24460000, 50000000, '현대 코나는 소형 SUV로, 개성 있는 디자인과 다양한 파워트레인 선택지가 강점인 모델이다. 파워트레인은 EV, 가솔린, 하이브리드 구성을 제공해 주행 성향과 유지비 기준에 맞춰 선택할 수 있다. 5인승 구조를 바탕으로 일상 주행과 가족 이동, 장거리 이동에 활용할 수 있다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 2,446만~5,000만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 코나는 소형 SUV로, 개성 있는 디자인과 다양한 파워트레인 선택지가 강점인 모델이다.'),
(1016, 'Tucson', '투싼', 1, 'Hyundai', '현대', 'suv', 'Compact', 'SUV', 5, 27710000, 43000000, '현대 투싼은 준중형 SUV로, 국내 SUV 시장에서 가장 대중적인 선택지 중 하나다. 파워트레인은 가솔린, 디젤, 하이브리드 구성을 제공해 주행 성향과 유지비 기준에 맞춰 선택할 수 있다. 5인승 구조를 바탕으로 일상 주행과 가족 이동, 장거리 이동에 활용할 수 있다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 2,771만~4,300만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 투싼은 준중형 SUV로, 국내 SUV 시장에서 가장 대중적인 선택지 중 하나다.'),
(1017, 'Pavise', '파비스', 1, 'Hyundai', '현대', 'truck', 'Commercial', 'Medium/Heavy Truck', 3, 80000000, 130000000, '현대 파비스는 중대형 트럭 라인업으로, 대형 화물 운송과 특장 목적에 맞춘 상용 모델이다. 디젤 파워트레인을 중심으로 장거리 주행 효율과 높은 토크를 제공한다. 3인승 구조와 적재 중심의 차체 구성을 바탕으로 물류, 업무, 레저, 사업용 운행에 적합하다. 주요 사양은 적재 형태와 특장 구성에 따라 달라지며, 내구성, 운행 효율, 업무 편의성이 중요한 선택 기준이다. 국내 판매 가격은 약 8,000만~13,000만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 파비스는 중대형 트럭 라인업으로, 대형 화물 운송과 특장 목적에 맞춘 상용 모델이다.'),
(1018, 'Porter II', '포터 II', 1, 'Hyundai', '현대', 'truck', 'Commercial', 'Light Truck', 3, 21520000, 46450000, '현대 포터 II는 국내 소형 트럭 시장의 대표 모델로, 자영업, 배송, 농업, 소규모 물류 등 다양한 생업 현장에서 널리 활용된다. LPG 파워트레인을 통해 연료비 부담을 낮추고 실용적인 운행이 가능하다. 3인승 구조와 적재 중심의 차체 구성을 바탕으로 물류, 업무, 레저, 사업용 운행에 적합하다. 주요 사양은 적재 형태와 특장 구성에 따라 달라지며, 내구성, 운행 효율, 업무 편의성이 중요한 선택 기준이다. 국내 판매 가격은 약 2,152만~4,645만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '현대 포터 II는 국내 소형 트럭 시장의 대표 모델로, 자영업, 배송, 농업, 소규모 물류 등 다양한 생업 현장에서 널리 활용된다.'),
(2001, 'EV3', 'EV3', 2, 'Kia', '기아', 'suv', 'Subcompact', 'Electric SUV', 5, 39950000, 51000000, '기아 EV3는 소형급 SUV / RV 모델로, 국내 공식 판매 라인업에서 실용성과 상품성을 중심으로 구성된 차량이다. 순수 전기 파워트레인을 기반으로 정숙한 주행감과 낮은 운행비, 충전 인프라 활용성을 제공한다. 5인승 구조를 바탕으로 일상 주행과 가족 이동, 장거리 이동에 활용할 수 있다. 주요 편의 및 안전 사양은 트림에 따라 달라지며, 운전자 보조 기능과 인포테인먼트, 실내 편의성이 주요 선택 기준이다. 국내 판매 가격은 약 3,995만~5,100만원 수준으로 볼 수 있다. 실제 구매 조건은 세부 트림, 옵션, 연식 및 프로모션에 따라 달라질 수 있다.', '기아 EV3는 소형급 SUV / RV 모델로, 국내 공식 판매 라인업에서 실용성과 상품성을 중심으로 구성된 차량이다.'),
