INSERT INTO video (vehicle_id, display_order, url, channel_name, title) VALUES
(1001, 1, 'https://www.youtube.com/embed/_ac_myAIQFY', '한상기 오토프레스 Han Sang Ki', '현대 ST1 카고 시승기, 1회 충전 주행거리 317km, 6,405만원(HyundaI ST1 Cargo Test Drive) - 2024.05.25'),
(1001, 2, 'https://www.youtube.com/embed/kbWAYrFPS_o', '한상기 오토프레스 Han Sang Ki', '현대차 ST1 안팎 리뷰(Hyundai ST1)- 2024.04.23'),
(1001, 3, 'https://www.youtube.com/embed/K3rY1T0kjFA', '김한용의 MOCAR', '현대 ST1 시승기, 이젠 전기 화물차 시대!...가격 4900만원, 냉동탑차 한번 충전 320km 주행 실험!'),
(1002, 1, 'https://www.youtube.com/embed/POggjzdZpOk', '한상기 오토프레스 Han Sang Ki', '현대 더 뉴 그랜저 2.5 시승기, 캘리그래피 풀 옵션 5,772만원(2027 Hyundai Grandeur 2.5 Test Drive) - 2026.05.28'),
(1002, 2, 'https://www.youtube.com/embed/yyZRzEpbxi4', '한상기 오토프레스 Han Sang Ki', '2025 현대 그랜저 하이브리드 시승기, 캘리그래피 풀 옵션 5,729만원(2025 Hyundai Grandeur Hybrid Test Drive) - 2024.08.26'),
(1002, 3, 'https://www.youtube.com/embed/4zqI_OMuXuI', '한상기 오토프레스 Han Sang Ki', '현대 더 뉴 그랜저 가솔린 3.3 GDI 캘리그래피 시승기(2020 Hyundai Grandeur 3.3 GDi Test Drive) - 2019.11.19'),
(1002, 4, 'https://www.youtube.com/embed/FxbEcgIj8qc', '한상기 오토프레스 Han Sang Ki', '현대 신형 그랜저 GN7 3.5 AWD 시승기, 캘리그래피 풀 옵션 5,605만원(2023 Hyundai Grandeur Test Drive) - 2022.12.08'),
(1002, 5, 'https://www.youtube.com/embed/lPRMr-KgE7Y', '한상기 오토프레스 Han Sang Ki', '현대 신형 그랜저 하이브리드 시승기, 캘리그래피 풀 옵션 5,563만원(2023 Hyundai Grandeur Hybrid Test Drive) - 2022.12.14'),
(1002, 6, 'https://www.youtube.com/embed/QxpAAMl_i9Y', '차,또바기 - 디테일한 자동차 리뷰.', 'E클래스 오너의 2020 더 뉴 그랜저 2.5 캘리그라피 시승기! 이상하게 그랜저에서 벤츠의 느낌이 난다? 그랜저 타고 다니면 성공한 기분이 드는 이유! 역대급 완성도의 그랜저!'),
(1003, 1, 'https://www.youtube.com/embed/exYQ340hBIw', '한상기 오토프레스 Han Sang Ki', '현대 신형 넥쏘 시승기, 1회 충전 주행거리 720km, 프레스티지 풀 옵션 8,793만원(2026 Hyundai Nexo Test Drive) - 2025.06.18'),
(1003, 2, 'https://www.youtube.com/embed/GjnN606cesw', '김한용의 MOCAR', '현대 넥쏘 시승기, 매끄러운 승차감이 대박!...수소시대 미리 경험하는 차!'),
(1003, 3, 'https://www.youtube.com/embed/Zsq5jw4b8Yg', '김한용의 MOCAR', '신형 넥쏘 시승기, 이젠 수소차인가...오디오 바이 뱅앤올룹슨이 뭔데?'),
(1003, 4, 'https://www.youtube.com/embed/V7kJUYl-y74', '김한용의 MOCAR', '수소전기차 넥쏘, 트럭, 버스 심지어 쓰레기차까지 시승기!…평택시가 ''수소도시'' 되려는 이유 알아보자!'),
(1003, 5, 'https://www.youtube.com/embed/wm5bBQJ5Ua0', '김한용의 MOCAR', '현대 넥쏘 시승기…수소전기차, 진심 탈만 하냐? (네차 어때)'),
(1004, 1, 'https://www.youtube.com/embed/FiRFrcDE0go', '오토뷰(AutoView) - 자동차 & 타이어 구입 참고서', '[리뷰] 2026 현대 팰리세이드 하이브리드 / 오토뷰 로드테스트'),
(1004, 2, 'https://www.youtube.com/embed/WqiiYlCve54', '한상기 오토프레스 Han Sang Ki', '현대 팰리세이드 7인승 디젤 HTRAC 시승기 2부 주행편, 가속력은 괜찮지만 진동과 소음 대책은 미흡(2020 Hyundai Palisade Review) - 2018.12.11'),
(1004, 3, 'https://www.youtube.com/embed/DVFh7IX1QHI', '한상기 오토프레스 Han Sang Ki', '현대 신형 팰리세이드 하이브리드 9인승 AWD 시승기, 캘리그래피 6,888만원(2026 Hyundai Palisade Hybrid Test Drive) - 2025.04.16'),
(1004, 4, 'https://www.youtube.com/embed/yQyQxM-wRbc', '한상기 오토프레스 Han Sang Ki', '[비교시승기]팰리세이드 디젤 2.2 vs 가솔린 3.8 & 7인승 vs 8인승(Palisade 3.8 vs 2.2 HTRAC) - 2019.01.10'),
(1004, 5, 'https://www.youtube.com/embed/72m1NSu4t0I', '주니tv', '디 올 뉴 팰리세이드 2.5터보 4륜구동 캘리그래피 시승기, 2026 Hyundai Palisade 2.5T-GDi AWD test drive, review'),
(1005, 1, 'https://www.youtube.com/embed/mUity3yJVmg', '한상기 오토프레스 Han Sang Ki', '11년 만에 현대 마이티 타봤습니다, 2027 더 뉴 마이티 앨리슨 6단 시승기, 더 뉴 파비스 동승 - 2026.05.07'),
(1005, 2, 'https://www.youtube.com/embed/vgFo7FVLFIk', '트럭청년', '현대 마이티 3.5톤윙바디 1년운행 리뷰!'),
(1005, 3, 'https://www.youtube.com/embed/MeAI2mEq3TU', '카링TV carringTV', '마이티 전자동 변속기 15만 주행 후기, 마이티 자동 수동 고민 중이라면'),
(1006, 1, 'https://www.youtube.com/embed/ss3MGH8AlFA', '오토뷰(AutoView) - 자동차 & 타이어 구입 참고서', '쓸만한 소형 SUV...현대 베뉴 시승기 2019 4K (UHD) / Hyundai VENUE Roadtest (Test Drive)'),
(1006, 2, 'https://www.youtube.com/embed/MQt9GhilS_Q', '한상기 오토프레스 Han Sang Ki', '현대 베뉴 스마트스트림 1.6 가솔린 시승기(2020 Hyundai Venue SmartStream G1.6 Test Drive) - 2019.0711'),
(1006, 3, 'https://www.youtube.com/embed/8dwOpa8nwz8', '모트라인 MOTline', '좋아서 좋다고 말하는거에요 [베뉴, 모트라인 윤성로 리뷰]'),
(1006, 4, 'https://www.youtube.com/embed/h0UWWOkf7Yk', '김한용의 MOCAR', '현대차 베뉴, 생방송 시승기…작아서 좋은 SUV? 실드 쳐보겠습니다!'),
(1006, 5, 'https://www.youtube.com/embed/MpiV-7xiIv4', '김한용의 MOCAR', '현대차 베뉴 진짜 시승기...실드 쳐드리려고 했는데, 죄송합니다'),
(1007, 1, 'https://www.youtube.com/embed/IrY-Ur4OojQ', '한상기 오토프레스 Han Sang Ki', '현대 스타리아 라운지 7인승 2.2 디젤 HTRAC 시승기, 인스퍼레이션 4,680만원(Hyundai Staria Lounge 7Seater Review) - 2021.04.14'),
(1007, 2, 'https://www.youtube.com/embed/fSyjWOfaVRs', '한상기 오토프레스 Han Sang Ki', '현대 더 뉴 스타리아 일렉트릭 & 스타리아 라운지 리무진 안팎 리뷰(Hyundai Staria Electric) - 2026.04.21'),
(1007, 3, 'https://www.youtube.com/embed/f7aNZegyvFg', '한상기 오토프레스 Han Sang Ki', '2024 현대 스타리아 라운지 7인승 1.6 하이브리드 시승기, 인스퍼레이션 풀 옵션 4,946만원(Staria Hybrid Test Drive) - 2024.03.19'),
(1007, 4, 'https://www.youtube.com/embed/GgTzzVKNB2c', '홍시car', '스타리아 하이브리드 시승기! - 연비 15km나왔습니다! 승차감은 확실히 더 좋아요!'),
(1008, 1, 'https://www.youtube.com/embed/erdirmILgk8', '오토플레이 KR', '2026 현대 싼타페 시승기 / 가솔린 2륜 캘리그래피 6인승'),
(1008, 2, 'https://www.youtube.com/embed/7ToBjhkHAnY', '한상기 오토프레스 Han Sang Ki', '베이징현대 싼타페DM 2.4 GDI 시승기(Beijing Hyundai Santa Fe 2.4 GDI Review) - 2018.04.16'),
(1008, 3, 'https://www.youtube.com/embed/6mEfL6jCmTQ', '한상기 오토프레스 Han Sang Ki', '현대 신형 싼타페 하이브리드 4WD 6인승 시승기, 캘리그래피 풀옵션 5,516만원(2024 Hyundai Santa Fe Hybrid Test Drive) - 2023.11.16'),
(1008, 4, 'https://www.youtube.com/embed/dlimWdmR56Q', '한상기 오토프레스 Han Sang Ki', '현대 신형 싼타페(MX5) 2.5 가솔린 터보 시승기, 캘리그래피 풀 옵션 4,818만원(2024 Hyundai Santa Fe Test Drive) - 2023.08.24'),
(1008, 5, 'https://www.youtube.com/embed/VUOTbyo3ADQ', '한상기 오토프레스 Han Sang Ki', '현대 더 뉴 싼타페 디젤 2.2 캘리그래피 7인승 시승기, 4755만원 풀 옵션 사양(2021 Hyundai Santa Fe Test Drive) - 2020.07.02'),
(1008, 6, 'https://www.youtube.com/embed/KeWTWldhtLI', '한상기 오토프레스 Han Sang Ki', '현대 더 뉴 싼타페 하이브리드 시승기, 캘리그래피 2WD 7인승 4,791만원(2021 Hyundai Santa Fe Hybrid Test Drive) - 2021.07.24'),
(1008, 7, 'https://www.youtube.com/embed/UmbVLnSI4as', '김한용의 MOCAR', '현대 신형 싼타페 최초 시승기...쏘렌토와 비교해보니! - 시승차: 2.5T 2WD 풀옵션 가격 4833만원'),
(1009, 1, 'https://www.youtube.com/embed/PYPVTawNM94', '오토뷰(AutoView) - 자동차 & 타이어 구입 참고서', '[리뷰] 2023 현대 쏘나타 디엣지 하이브리드 (hyundai sonata hybrid roadtest) / 오토뷰 로드테스트'),
(1009, 2, 'https://www.youtube.com/embed/dn4U44_RJtY', '한상기 오토프레스 Han Sang Ki', '2024년형 현대 쏘나타 디 엣지 하이브리드 시승기, 프리미엄 트림 3,212만원(2024 Hyundai Sonata Hybrid Test Drive) - 2026.03.17'),
(1009, 3, 'https://www.youtube.com/embed/k_TRxk0557w', '한상기 오토프레스 Han Sang Ki', '현대 쏘나타 디 엣지 1.6 터보 & 2.5 N 라인 시승기, 인스퍼레이션 풀 옵션 3,934만원(2024 Hyundai Sonata Test Drive) - 2023.05.10'),
(1009, 4, 'https://www.youtube.com/embed/oISe88g80Ls', '한상기 오토프레스 Han Sang Ki', '현대 신형 쏘나타 센슈어스 1.6 터보 인스퍼레이션 시승기(2020 Hyundai Sonata 1.6 Turbo Test Drive) - 2019.10.22'),
(1010, 1, 'https://www.youtube.com/embed/kkuUdGBy4w0', '한상기 오토프레스 Han Sang Ki', '베이징 현대 엘란트라 1.5 MPI 시승기, GLX 2,520만원(Beijing Hyundai Elantra Test Drive) - 2026.04.25'),
