-- ============================================================

-- ==========================================================
-- 2. 테스트 데이터 삽입 (DML)
-- ==========================================================

-- 유저 데이터

/* SELECT * FROM user; */

-- 브랜드/차량/연료/영상 데이터는 accel_data.sql 에서 삽입

-- 1. 브랜드

-- 2. 차량
UPDATE brand SET is_domestic = TRUE WHERE brand_id IN (1, 2, 3, 4, 5, 6);


-- 3. 연료 타입

-- 4. 영상 (차량별 우선순위 영상 + 채널 다양화/썸네일 비-MOCAR 보강, YouTube Data API v3)

-- ==========================================================
-- 5. 브랜드 게시판 더미 게시글 (브랜드당 20개)
-- ==========================================================
    user_id,
    title,
    content,
    created_at,
    updated_at,
    test_drive_available,
    view_cnt,
    board_name,
    brand_id
)
SELECT
    ELT(MOD(b.brand_id + post_seed.post_no, 5) + 1, 'admin', 'test1', 'test2', 'test3', 'test4') AS user_id,
    CONCAT('[', b.brand_name, '] ', brand_seed.title_theme, ' - ', post_seed.title) AS title,
    CONCAT(
        b.brand_name, ' 게시판 더미 글입니다. ',
        brand_seed.opening, ' ',
        post_seed.content, ' ',
        brand_seed.detail_note, ' ',
        IF(post_seed.test_drive_available = 1, '이번 글은 시승 가능 여부를 TRUE로 둔 후기형 게시글입니다.', '이번 글은 시승 가능 여부를 FALSE로 둔 정보 공유형 게시글입니다.')
    ) AS content,
    TIMESTAMPADD(DAY, -((b.brand_id * 2) + post_seed.post_no), CURRENT_TIMESTAMP) AS created_at,
    TIMESTAMPADD(HOUR, post_seed.update_hours, TIMESTAMPADD(DAY, -((b.brand_id * 2) + post_seed.post_no), CURRENT_TIMESTAMP)) AS updated_at,
    IF(post_seed.test_drive_available = 1, TRUE, FALSE) AS test_drive_available,
    MOD((b.brand_id * 37) + (post_seed.post_no * 11), 480) + 12 AS view_cnt,
    b.brand_name AS board_name,
    b.brand_id
FROM brand b
JOIN (
    SELECT 1 AS brand_id, '아이오닉과 패밀리 라인업 기준' AS title_theme, '현대는 일상형 전동화와 넓은 선택지를 기준으로 살펴봤습니다.' AS opening, '아이오닉, 그랜저, 팰리세이드처럼 가족/출퇴근 수요가 많은 모델을 염두에 둔 내용입니다.' AS detail_note
    UNION ALL SELECT 2, 'EV 라인업과 실용성 기준', '기아는 EV 시리즈와 SUV 중심의 실용 구성을 기준으로 살펴봤습니다.', 'EV3, EV6, 쏘렌토, 카니발처럼 생활 반경이 넓은 모델을 함께 비교하는 분위기입니다.'
    UNION ALL SELECT 3, '프리미엄 세단과 SUV 기준', '제네시스는 정숙성, 승차감, 실내 소재감을 중심으로 정리했습니다.', 'G80, GV70, GV80을 고민하는 사용자가 볼 만한 포인트를 넣었습니다.'
    UNION ALL SELECT 4, '아메리칸 SUV와 픽업 기준', '쉐보레는 튼튼한 차체감과 장거리 주행 안정감을 기준으로 살펴봤습니다.', '트랙스, 트레일블레이저, 콜로라도처럼 개성이 다른 모델을 상상한 내용입니다.'
    UNION ALL SELECT 5, '가성비 SUV와 픽업 기준', 'KGM은 가격 대비 공간과 유지비를 중심으로 봤습니다.', '토레스, 렉스턴, 무쏘처럼 실사용 장비를 싣는 상황을 염두에 뒀습니다.'
    UNION ALL SELECT 6, '르노 하이브리드 감각 기준', '르노는 부드러운 주행감과 독특한 디자인 취향을 기준으로 정리했습니다.', '아르카나와 그랑 콜레오스처럼 도심형 패밀리 SUV 흐름에 맞춘 이야기입니다.'
    UNION ALL SELECT 7, '벤츠 승차감과 브랜드 경험 기준', '메르세데스-벤츠는 고급감, 조용함, 주행 보조 완성도를 기준으로 봤습니다.', 'E클래스, GLC, S클래스처럼 체급별 기대치가 다른 모델을 떠올린 내용입니다.'
    UNION ALL SELECT 8, 'BMW 주행감과 옵션 기준', 'BMW는 운전 재미와 실내 기술 구성을 중심으로 살펴봤습니다.', '3시리즈, 5시리즈, X 라인업처럼 직접 몰아보는 재미가 중요한 상황을 반영했습니다.'
    UNION ALL SELECT 9, '아우디 콰트로와 실내 감성 기준', '아우디는 단정한 실내와 안정적인 주행감을 기준으로 정리했습니다.', 'A5, Q5, e-tron 계열을 비교하는 사용자가 볼 만한 관점입니다.'
    UNION ALL SELECT 10, '폭스바겐 기본기와 실속 기준', '폭스바겐은 과하지 않은 디자인과 기본기를 중심으로 봤습니다.', '골프, 티구안, 투아렉처럼 오래 타는 실용차 관점의 내용입니다.'
    UNION ALL SELECT 11, '포르쉐 주행 질감 기준', '포르쉐는 스티어링 감각과 고속 안정성을 기준으로 살펴봤습니다.', '911, 카이엔, 마칸처럼 스포츠성과 일상을 함께 보는 분위기입니다.'
    UNION ALL SELECT 12, '테슬라 충전과 소프트웨어 기준', '테슬라는 충전 동선, OTA, 간결한 실내 사용성을 중심으로 정리했습니다.', '모델3, 모델Y, 사이버트럭처럼 전기차 경험 자체를 비교하는 내용입니다.'
    UNION ALL SELECT 13, '포드 픽업과 머슬 감성 기준', '포드는 넉넉한 힘과 아웃도어 활용성을 기준으로 봤습니다.', '브롱코, 익스플로러, 머스탱처럼 성격이 뚜렷한 모델을 떠올렸습니다.'
    UNION ALL SELECT 14, '지프 오프로드와 감성 기준', '지프는 험로 대응과 개성 있는 디자인을 중심으로 정리했습니다.', '랭글러, 글래디에이터, 어벤저처럼 취향이 분명한 모델에 맞춘 내용입니다.'
    UNION ALL SELECT 15, '캐딜락 대형 SUV와 전기차 기준', '캐딜락은 큰 차체, 고급 편의 사양, 전기 SUV 흐름을 기준으로 봤습니다.', '에스컬레이드와 리릭처럼 존재감이 큰 모델을 비교하는 문맥입니다.'
    UNION ALL SELECT 16, '토요타 하이브리드 신뢰성 기준', '토요타는 하이브리드 효율과 장기 유지 안정성을 중심으로 살펴봤습니다.', '캠리, 라브4, 프리우스처럼 연비와 내구성을 중시하는 사용자를 떠올렸습니다.'
    UNION ALL SELECT 17, '렉서스 정숙성과 품질 기준', '렉서스는 조용한 실내와 부드러운 승차감을 기준으로 정리했습니다.', 'ES, RX, NX처럼 가족용 럭셔리카를 고민하는 분위기에 맞췄습니다.'
    UNION ALL SELECT 18, '혼다 실용성과 패밀리 기준', '혼다는 넓은 실내와 무난한 조작감을 중심으로 살펴봤습니다.', '어코드, CR-V, 오딧세이처럼 오래 쓰기 좋은 구성을 기준으로 했습니다.'
    UNION ALL SELECT 19, '볼보 안전과 북유럽 감성 기준', '볼보는 안전 사양, 시트 편안함, 담백한 디자인을 중심으로 봤습니다.', 'XC60, XC90, EX30처럼 가족 안전을 우선하는 사용자를 떠올렸습니다.'
    UNION ALL SELECT 20, 'MINI 개성과 도심 주행 기준', 'MINI는 작은 차체의 경쾌함과 디자인 취향을 기준으로 정리했습니다.', '쿠퍼, 에이스맨, 컨트리맨처럼 도심 주행 감각이 중요한 내용입니다.'
    UNION ALL SELECT 21, '푸조 디자인과 효율 기준', '푸조는 독특한 실내 구성과 효율적인 파워트레인을 중심으로 봤습니다.', '2008, 3008, 5008처럼 프랑스차 감성을 찾는 사용자를 떠올렸습니다.'
    UNION ALL SELECT 22, '랜드로버 공간과 오프로드 기준', '랜드로버는 험로 감각과 고급 SUV 경험을 기준으로 살펴봤습니다.', '디펜더, 디스커버리, 레인지로버처럼 활용 폭이 큰 모델을 반영했습니다.'
    UNION ALL SELECT 23, '폴스타 전기차와 미니멀 기준', '폴스타는 전기차 주행감과 절제된 인테리어를 중심으로 정리했습니다.', '폴스타2와 폴스타4처럼 차분한 전기차 취향에 맞춘 내용입니다.'
    UNION ALL SELECT 24, 'BYD 전기차 가성비 기준', 'BYD는 배터리 기술과 가격 경쟁력을 중심으로 봤습니다.', '아토3처럼 새롭게 유입되는 전기차 구매자를 상상했습니다.'
    UNION ALL SELECT 25, '페라리 슈퍼카 감성 기준', '페라리는 엔진 감각과 브랜드 상징성을 중심으로 정리했습니다.', '296, 로마, 푸로산게처럼 일상보다 감성이 중요한 글 분위기입니다.'
    UNION ALL SELECT 26, '람보르기니 퍼포먼스 기준', '람보르기니는 강렬한 디자인과 폭발적인 출력감을 기준으로 봤습니다.', '레부엘토, 테메라리오, 우루스처럼 시각적 존재감이 큰 모델을 떠올렸습니다.'
    UNION ALL SELECT 27, '롤스로이스 럭셔리 경험 기준', '롤스로이스는 압도적인 정숙성과 개인화 옵션을 중심으로 살펴봤습니다.', '고스트, 팬텀, 컬리넌처럼 쇼퍼드리븐 감각을 담은 내용입니다.'
    UNION ALL SELECT 28, '벤틀리 GT와 럭셔리 SUV 기준', '벤틀리는 고급 소재와 장거리 그랜드 투어링 감각을 기준으로 봤습니다.', '벤테이가, 컨티넨탈 GT, 플라잉스퍼처럼 편안한 고성능을 떠올렸습니다.'
    UNION ALL SELECT 29, '마세라티 사운드와 디자인 기준', '마세라티는 이탈리안 감성과 배기 사운드 이미지를 중심으로 정리했습니다.', '그란투리스모, 그레칼레, MC20처럼 취향이 중요한 모델을 반영했습니다.'
    UNION ALL SELECT 30, '애스턴마틴 GT 감성 기준', '애스턴마틴은 우아한 디자인과 GT 주행감을 기준으로 살펴봤습니다.', 'DB12, DBX, 밴티지처럼 멋과 속도를 같이 보는 글입니다.'
    UNION ALL SELECT 31, '맥라렌 경량 슈퍼카 기준', '맥라렌은 가벼운 차체와 트랙 지향 감각을 중심으로 봤습니다.', '750S, 아투라, W1처럼 퍼포먼스 중심 모델을 떠올렸습니다.'
) brand_seed ON brand_seed.brand_id = b.brand_id
CROSS JOIN (
    SELECT 1 AS post_no, '실차 보고 온 후기' AS title, '전시장에 들러 외관과 실내를 직접 확인했습니다. 사진보다 차체 비율이 자연스럽고 조작계도 금방 익숙해지는 편이었습니다.' AS content, 1 AS test_drive_available, 1 AS update_hours
    UNION ALL SELECT 2, '시승 예약 팁 공유', '주말 시승은 예약이 빨리 차서 평일 오전이나 점심 직후 시간이 여유로웠습니다. 동승자와 함께 가면 공간감 확인에 도움이 됩니다.', 1, 2
    UNION ALL SELECT 3, '패밀리카로 괜찮을까요', '카시트와 유모차를 같이 싣는 상황을 기준으로 보고 있습니다. 뒷좌석 승하차와 트렁크 턱 높이가 가장 궁금합니다.', 0, 3
    UNION ALL SELECT 4, '전기차 충전 경험', '아파트 완속 충전과 고속도로 급속 충전을 함께 써보니 충전 계획만 잡으면 일상 주행은 크게 부담스럽지 않았습니다.', 1, 4
    UNION ALL SELECT 5, '출고 대기 기간 공유', '최근 상담 기준으로 인기 색상과 상위 트림은 대기 기간이 조금 더 길었습니다. 계약 전에 재고차 여부도 꼭 확인해보세요.', 0, 5
    UNION ALL SELECT 6, '옵션 구성 추천 부탁', '안전 보조와 통풍 시트는 우선순위가 높은데, 외장 패키지까지 넣을지 고민입니다. 실제 만족도가 높은 옵션이 궁금합니다.', 0, 6
    UNION ALL SELECT 7, '장거리 주행 느낌', '고속도로 위주로 오래 달렸을 때 직진 안정감과 시트 지지감이 중요했습니다. 휴게소 한 번 쉬고 나면 피로가 꽤 줄었습니다.', 1, 7
    UNION ALL SELECT 8, '실내 공간 체감', '수치로 보는 것보다 2열 무릎 공간과 머리 공간 체감이 더 중요했습니다. 가족들이 직접 앉아보는 과정이 제일 확실했습니다.', 0, 8
    UNION ALL SELECT 9, '연비 전비 기록 공유', '출퇴근과 주말 이동을 섞어 기록해보니 공조 사용과 정체 구간 영향이 컸습니다. 같은 차라도 주행 패턴에 따라 차이가 큽니다.', 0, 9
    UNION ALL SELECT 10, '중고 구매 체크 포인트', '보증 잔여 기간, 사고 이력, 타이어 마모, 소모품 교체 내역을 먼저 확인했습니다. 시운전 때 하체 소음도 꼭 들어보세요.', 0, 10
    UNION ALL SELECT 11, '디자인 실물 느낌', '실물은 사진보다 선이 또렷하고 컬러에 따라 인상이 많이 달라집니다. 밝은 색은 차가 커 보이고 어두운 색은 안정감이 있습니다.', 0, 11
    UNION ALL SELECT 12, '정비 비용 궁금합니다', '공식 서비스센터와 사설 정비 비용 차이가 어느 정도인지 궁금합니다. 보증 이후 유지비 경험담이 있으면 공유 부탁드립니다.', 0, 12
    UNION ALL SELECT 13, '초보 운전자 질문', '차폭감과 주차 보조 기능을 중점적으로 보고 있습니다. 처음 운전하는 사람에게 부담이 적은 트림이나 옵션이 있을까요.', 0, 13
    UNION ALL SELECT 14, '캠핑 차박 사용 후기', '2열 폴딩 후 매트를 깔아봤을 때 바닥 단차와 전원 사용성이 중요했습니다. 주말 나들이용으로는 수납 구성이 꽤 중요합니다.', 1, 14
    UNION ALL SELECT 15, '고속도로 주행 안정감', '차선 유지 보조와 어댑티브 크루즈를 함께 쓰면 장거리 피로가 줄었습니다. 다만 비 오는 날 센서 상태는 계속 확인해야 합니다.', 1, 15
    UNION ALL SELECT 16, '도심 주차 난이도', '주차장 램프와 기계식 주차 가능 여부를 먼저 확인했습니다. 360도 카메라가 있으면 좁은 골목에서 마음이 훨씬 편합니다.', 0, 16
    UNION ALL SELECT 17, '하이브리드 만족도', '정체 구간에서는 전기모터 개입이 많아 조용하고 부드럽습니다. 연료비보다 정숙성과 저속 응답이 더 크게 체감됐습니다.', 1, 17
    UNION ALL SELECT 18, '소음과 승차감 비교', '노면 소음은 타이어와 휠 크기에 따라 차이가 컸습니다. 승차감을 우선한다면 큰 휠보다 기본 휠 조합도 고려할 만합니다.', 0, 18
    UNION ALL SELECT 19, '계약 전 마지막 고민', '가격, 옵션, 출고 시기까지 정리해보니 결국 실사용 목적이 기준이 되었습니다. 오래 탈 차라면 시승은 꼭 해보는 쪽을 추천합니다.', 0, 19
    UNION ALL SELECT 20, '오너들이 추천하는 트림', '가성비 트림과 풀옵션 사이에서 고민 중입니다. 실제 오너분들이 다시 산다면 어떤 구성을 고를지 의견 부탁드립니다.', 1, 20
) post_seed
LEFT JOIN (
    SELECT vh.brand_id, vd.display_order, MIN(vd.url) AS url
    FROM vehicle vh
    JOIN video vd ON vd.vehicle_id = vh.vehicle_id
    GROUP BY vh.brand_id, vd.display_order
) brand_image ON brand_image.brand_id = b.brand_id
    AND brand_image.display_order = MOD(post_seed.post_no - 1, 6) + 1
ORDER BY b.brand_id, post_seed.post_no;

SELECT
    a.article_id,
    CONCAT('https://placehold.co/640x360/111827/ffffff.png?text=', REPLACE(a.board_name, ' ', '+'), '+', a.article_id),
    0
FROM article a
WHERE NOT EXISTS (
    SELECT 1
    FROM article_img ai
    WHERE ai.article_id = a.article_id
);

-- ==========================================================
-- 6. 브랜드 게시판 더미 댓글 (게시글당 3개)
-- ==========================================================
    user_id,
    content,
    created_at,
    updated_at,
    article_id
)
SELECT
    ELT(MOD(a.article_id + comment_seed.comment_no, 5) + 1, 'test1', 'test2', 'test3', 'test4', 'admin') AS user_id,
    CONCAT(
        comment_seed.content, ' ',
        a.board_name, ' 기준으로는 ',
        IF(a.test_drive_available, '시승 일정을 같이 잡아보면 판단이 더 쉬울 것 같아요.', '조건표와 유지비를 먼저 비교해보면 좋겠습니다.'),
        ' 관심 글: ', LEFT(a.title, 40)
    ) AS content,
    TIMESTAMPADD(MINUTE, comment_seed.minute_offset, a.created_at) AS created_at,
    TIMESTAMPADD(MINUTE, comment_seed.minute_offset, a.created_at) AS updated_at,
    a.article_id
FROM article a
CROSS JOIN (
    SELECT 1 AS comment_no, '좋은 정보 감사합니다. 실제 구매 고민할 때 도움이 될 것 같아요.' AS content, 18 AS minute_offset
    UNION ALL SELECT 2, '저도 비슷하게 보고 있는데 옵션 조합이 제일 어렵네요.', 47
    UNION ALL SELECT 3, '시승 예약 가능하면 주말에 직접 확인해보고 후기 남기겠습니다.', 96
) comment_seed
WHERE a.title LIKE '[%] %'
ORDER BY a.article_id, comment_seed.comment_no;
